code.C:
#include <stdio.h>
int main() {
    char str[11];
    scanf("%s", str);
    int count4 = 0, count7 = 0;
    for (int i = 0; str[i] != '\0'; i++) {
        if (str[i] == '4') count4++;
        else if (str[i] == '7') count7++;
    }
    if (count4 == count7 || (count4 == 0 && count7 == 0)) printf("YES\n");
    else printf("NO\n");
    return 0;
}

